        });

        // Remove dangerous header before forwarding to origin
        const newHeaders = new Headers(request.headers);
        newHeaders.delete(header);

        request = new Request(request, { headers: newHeaders });
      }
    }

    // Create cache key including security-relevant components
    const cacheKeyComponents = [
      method,
      url.hostname,
      url.pathname,
      url.search
    ];

    // Include important headers in cache key
    const keyedHeaders = [
      'accept-language',
      'accept-encoding',
      'authorization',
      'cookie'
    ];

    for (const header of keyedHeaders) {
      const value = request.headers.get(header);
      if (value) {
        cacheKeyComponents.push(`${header}:${value}`);
      }
    }

    // Create normalized cache key
    const cacheKey = cacheKeyComponents.join('|');
    const cacheUrl = new Request(url.toString(), {
      method: method,
      headers: request.headers
    });

    // Check cache first
    const cache = caches.default;
    let response = await cache.match(cacheKey);

    if (!response) {
      // Forward to origin with security headers
      response = await fetch(request);

      // Only cache responses that are safe to cache
      const shouldCache = (
        response.status === 200 &&
        method === 'GET' &&
        !response.headers.has('set-cookie') &&
        !request.headers.has('authorization') &&
        !request.headers.has('cookie')
      );

      if (shouldCache) {
        // Clone response to cache
        const responseToCache = response.clone();

        // Add security headers to cached response
        const cachedHeaders = new Headers(responseToCache.headers);

        // Add Vary headers to declare cache key dependencies
        const varyHeaders = keyedHeaders.join(', ');
        cachedHeaders.set('Vary', varyHeaders);

        // Add cache control with appropriate TTL
        cachedHeaders.set('Cache-Control', 'public, max-age=3600, s-maxage=3600');

        // Add security headers
        cachedHeaders.set('X-Content-Type-Options', 'nosniff');
        cachedHeaders.set('X-Frame-Options', 'DENY');
        cachedHeaders.set('Content-Security-Policy', "default-src 'self'");

        // Create new response with security headers
        const secureResponse = new Response(responseToCache.body, {
          status: responseToCache.status,
          statusText: responseToCache.statusText,
          headers: cachedHeaders
        });

        // Store in cache using normalized key
        ctx.waitUntil(cache.put(cacheKey, secureResponse.clone()));

        return secureResponse;
      }
    }

    // Add cache status header
    const headers = new Headers(response.headers);
    headers.set('X-Cache-Status', response ? 'HIT' : 'MISS');

    return new Response(response.body, {
      status: response.status,
      statusText: response.statusText,
      headers: headers
    });
  }
};

