# Flask application with web cache deception prevention
# Implements strict path normalization and cache headers

from flask import Flask, request, make_response, abort, jsonify
import re
import hashlib
import hmac
from functools import wraps
from urllib.parse import urlparse, unquote

app = Flask(__name__)

# Configuration
APP_SECRET = 'your-secret-key-change-in-production'
STATIC_EXTENSIONS = {'.css', '.js', '.jpg', '.jpeg', '.png', '.gif', '.svg', '.woff', '.woff2', '.ttf', '.ico'}
DYNAMIC_PATHS = {'/api', '/admin', '/account', '/user', '/auth', '/login', '/logout', '/profile'}

def normalize_path(path):
    """Normalize URL path to prevent path confusion attacks."""
    # Decode URL encoding
    path = unquote(path)

    # Remove multiple slashes
    path = re.sub(r'/+', '/', path)

    # Remove trailing slash
    path = path.rstrip('/')

    # Resolve . and .. segments
    parts = []
    for part in path.split('/'):
        if part == '..' and parts:
            parts.pop()
        elif part and part != '.':
            parts.append(part)

    normalized = '/' + '/'.join(parts)
    return normalized if normalized else '/'

def extract_extension(path):
    """Extract file extension from path."""
    # Only consider the last real path segment, not fake extensions
    segments = [s for s in path.split('/') if s]
    if not segments:
        return None

    last_segment = segments[-1]
    if '.' in last_segment:
        return '.' + last_segment.rsplit('.', 1)[-1].lower()
    return None

def is_static_resource(path):
    """Determine if path should be treated as static resource."""
    normalized = normalize_path(path)
    extension = extract_extension(normalized)

    # Check if path is under static directory
    if normalized.startswith('/static/'):
        return extension in STATIC_EXTENSIONS

    # Any other path with static extension is suspicious
    return False

def prevent_cache_deception():
    """Decorator to prevent web cache deception attacks."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            request_path = request.path
            normalized_path = normalize_path(request_path)

            # Check for path confusion indicators
            suspicious_patterns = [
                r'/.*\.css$',        # Fake CSS extension
                r'/.*\.js$',         # Fake JS extension
                r'/.*\.jpg$',        # Fake image extension
                r'/.*\.(png|gif|svg)$'
            ]

            # Check if this is a dynamic endpoint with fake static extension
            is_dynamic = any(normalized_path.startswith(prefix) for prefix in DYNAMIC_PATHS)
            has_static_extension = extract_extension(normalized_path) in STATIC_EXTENSIONS

            if is_dynamic and has_static_extension:
                app.logger.warning(
                    f'Web cache deception attempt detected: {request_path}',
                    extra={
                        'client_ip': request.remote_addr,
                        'user_agent': request.headers.get('User-Agent'),
                        'normalized_path': normalized_path
                    }
                )
                abort(404)  # Return 404 instead of actual content

            # Verify path normalization matches request
            if normalized_path != request_path.rstrip('/'):
                # Redirect to normalized path to prevent cache confusion
                return make_response('', 301, {'Location': normalized_path})

            response = make_response(f(*args, **kwargs))

            # Set cache headers based on resource type
            if is_static_resource(request_path):
                # Static resources: cacheable
                response.headers['Cache-Control'] = 'public, max-age=31536000, immutable'
                response.headers['Vary'] = 'Accept-Encoding'
            else:
                # Dynamic resources: never cache
                response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate, private'
                response.headers['Pragma'] = 'no-cache'
                response.headers['Expires'] = '0'

            # Add security headers
            response.headers['X-Content-Type-Options'] = 'nosniff'
            response.headers['X-Frame-Options'] = 'DENY'

            return response
        return decorated_function
    return decorator

# Apply decorator to all routes
@app.before_request
def before_request():
    """Global request validation."""
    request_path = request.path
    normalized_path = normalize_path(request_path)

    # Block requests with suspicious path patterns
    if request_path != normalized_path.rstrip('/') and request_path.rstrip('/') != normalized_path:
        abort(400, 'Invalid path format')

@app.route('/api/user/profile')
@prevent_cache_deception()
def get_user_profile():
    """Example API endpoint - should never be cached."""
    user_id = request.headers.get('X-User-ID', 'anonymous')

    # Return user-specific data
    profile = {
        'user_id': user_id,
        'email': f'{user_id}@example.com',
        'sensitive_data': 'This should never be cached'
    }

    return jsonify(profile)

@app.route('/account/settings')
@prevent_cache_deception()
def account_settings():
    """Account settings page - authenticated, never cached."""
    if not request.headers.get('Authorization'):
        abort(401)

    return jsonify({
        'settings': 'User-specific settings',
        'api_key': 'sk_live_secret123'
    })

@app.route('/static/<path:filename>')
def serve_static(filename):
    """Serve static files with proper caching."""
    # Validate filename doesn't contain path traversal
    if '..' in filename or filename.startswith('/'):
        abort(400)

    extension = extract_extension(filename)
    if extension not in STATIC_EXTENSIONS:
        abort(404)

    response = make_response(send_from_directory('static', filename))
    response.headers['Cache-Control'] = 'public, max-age=31536000, immutable'
    response.headers['X-Content-Type-Options'] = 'nosniff'

    return response

@app.errorhandler(404)
def not_found(error):
    """Ensure 404 responses are never cached."""
    response = make_response(jsonify({'error': 'Not found'}), 404)
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate, private'
    return response

if __name__ == '__main__':
    app.run(debug=False, host='0.0.0.0', port=8080)

