// Express.js middleware for comprehensive cache control
// Prevents cache poisoning through explicit cache policies

const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security headers middleware
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'"],
      imgSrc: ["'self'", "data:"],
      connectSrc: ["'self'"]
    }
  },
  hsts: {
    maxAge: 31536000,
    includeSubDomains: true,
    preload: true
  }
}));

// Cache control configuration
const CACHE_POLICIES = {
  NO_CACHE: 'no-store, no-cache, must-revalidate, proxy-revalidate, private',
  STATIC_IMMUTABLE: 'public, max-age=31536000, immutable',
  STATIC_SHORT: 'public, max-age=3600, s-maxage=3600',
  DYNAMIC_SHORT: 'public, max-age=60, s-maxage=60, must-revalidate',
  PRIVATE: 'private, no-cache, no-store, must-revalidate'
};

// Middleware to set cache policies based on content type
function cacheControl(policy) {
  return (req, res, next) => {
    // Never cache error responses
    const originalSend = res.send;
    res.send = function(data) {
      if (res.statusCode >= 400) {
        res.set('Cache-Control', CACHE_POLICIES.NO_CACHE);
      }
      originalSend.call(this, data);
    };

    res.set('Cache-Control', policy);

    // Prevent CDN transformation
    res.set('Cache-Control', `${policy}, no-transform`);

    // Add Vary headers for content negotiation
    res.vary('Accept-Encoding');
    res.vary('Accept-Language');

    // Security headers to prevent cache poisoning
    res.set('X-Content-Type-Options', 'nosniff');
    res.set('X-Frame-Options', 'DENY');

    // Add CDN-Cache-Control for Cloudflare/Fastly
    if (policy.includes('public')) {
      const maxAge = policy.match(/max-age=(\d+)/);
      if (maxAge) {
        res.set('CDN-Cache-Control', `max-age=${maxAge[1]}`);
      }
    } else {
      res.set('CDN-Cache-Control', 'no-store');
    }

    next();
  };
}

// Middleware to detect and block cache poisoning attempts
function preventCachePoisoning(req, res, next) {
  const dangerousHeaders = [
    'x-forwarded-host',
    'x-forwarded-server',
    'x-original-url',
    'x-rewrite-url',
    'x-host'
  ];

  for (const header of dangerousHeaders) {
    if (req.headers[header]) {
      console.error('Cache poisoning attempt detected', {
        header: header,
        value: req.headers[header],
        ip: req.ip,
        path: req.path,
        timestamp: new Date().toISOString()
      });

      // Option 1: Block request
      return res.status(403).json({
        error: 'Forbidden',
        message: 'Dangerous header detected',
        code: 'CACHE_POISON_ATTEMPT'
      });

      // Option 2: Remove header and continue
      // delete req.headers[header];
    }
  }

  // Validate Host header matches expected domain
  const allowedHosts = ['example.com', 'www.example.com', 'cdn.example.com'];
  if (!allowedHosts.includes(req.hostname)) {
    console.error('Invalid Host header', {
      host: req.hostname,
      ip: req.ip,
      timestamp: new Date().toISOString()
    });
    return res.status(400).json({
      error: 'Bad Request',
      message: 'Invalid Host header'
    });
  }

  next();
}

// Apply cache poisoning prevention globally
app.use(preventCachePoisoning);

// Static assets with aggressive caching
app.use('/static', 
