# Cache Rules - Prevent cache poisoning
resource "cloudflare_ruleset" "cache_security" {
  zone_id     = var.zone_id
  name        = "Cache Security Rules"
  description = "Prevent cache poisoning and web cache deception"
  kind        = "zone"
  phase       = "http_request_cache_settings"

  rules {
    action = "set_cache_settings"
    description = "Never cache authenticated requests"
    enabled = true

    expression = "(http.request.uri.path contains \"/api/\" or http.request.uri.path contains \"/admin/\" or http.request.uri.path contains \"/account/\") and (http.request.headers[\"authorization\"][*] ne \"\" or http.request.headers[\"cookie\"][*] ne \"\")"

    action_parameters {
      cache = false
    }
  }

  rules {
    action = "set_cache_settings"
    description = "Block cache deception attempts - dynamic paths with static extensions"
    enabled = true

    expression = "(http.request.uri.path contains \"/api/\" or http.request.uri.path contains \"/admin/\") and (http.request.uri.path ends with \".css\" or http.request.uri.path ends with \".js\" or http.request.uri.path ends with \".jpg\")"

    action_parameters {
      cache = false
    }
  }

  rules {
    action = "set_cache_settings"
    description = "Aggressive caching for static assets"
    enabled = true

    expression = "http.request.uri.path starts with \"/static/\""

    action_parameters {
      cache = true
      edge_ttl {
        mode = "override_origin"
        default = 31536000  # 1 year
      }
      browser_ttl {
        mode = "override_origin"
        default = 31536000
      }
    }
  }
}

