}

# Security Level
resource "cloudflare_zone_settings_override" "security" {
  zone_id = var.zone_id

  settings {
    security_level = "high"
    cache_level    = "aggressive"

    # Enable Cloudflare security features
    browser_check  = "on"
    challenge_ttl  = 1800

    # Security headers
    security_header {
      enabled = true
      max_age = 31536000
      include_subdomains = true
      preload = true
      nosniff = true
    }

    # Disable potentially dangerous features
    opportunistic_encryption = "on"
    automatic_https_rewrites = "on"
  }
}

# Analytics configuration
resource "cloudflare_notification_policy" "cache_poisoning_alerts" {
  account_id = var.cloudflare_account_id
  name       = "Cache Poisoning Detection Alerts"
  description = "Alert on potential cache poisoning attempts"
  enabled    = true
  alert_type = "zone_custom_event"

  filters {
    zones = [var.zone_id]
  }

  email_integration {
    id = var.email_integration_id
  }
}

output "zone_id" {
  value = var.zone_id
}

output "cache_rules" {
  value = cloudflare_ruleset.cache_security.id
}

output "waf_rules" {
  value = cloudflare_ruleset.waf_security.id
}
